var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"1시간 전…… 그러니까, 협정 세계시를 기준으로 1시간 전에 벌어진 일이요.","JPN":"1時間前……つまり、協定世界時を基準に1時間前に起こったことだ。","ENG":"This happened an hour ago. Based on the agreed-upon world standard time, that is.","TWN":"1小時前……總之就是以世界協調時間為準，1小時前發生的事啦！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"망할 해적 놈들한테 우리 알파트릭스 그룹 소유의 연구선이 나포되었다더군.","JPN":"海賊に我がアルファトリックスグループ所有の研究船が拿捕されたそうだ。","ENG":"Some accursed pirates have stolen the Alphatrix group's research ship.","TWN":"那些該死的海盜，竟然搶走我們阿爾法崔克斯集團的研究船！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"함선 한 척 따윈 아깝지 않지만, 그 안에는 우리 그룹의 연구 데이터가 잔뜩 들어 있어.","JPN":"艦船一隻くらいくれてやってもいいが、その中には我が社の研究データが大量に搭載されている。","ENG":"I don't care about the ship, but I do care about the research data that it carries in it.","TWN":"損失區區一艘艦船沒什麼好心疼的，但那艘船裡面都是我們集團的研究資料。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"자, 여기까지 들었으면 의뢰 내용이 뭔지 대충 짐작 가겠지.","JPN":"さあ、ここまで聞いたなら依頼内容の見当がついただろう。","ENG":"There. I'm sure you can figure out the rest of my request.","TWN":"聽到這裡，你應該知道委託的內容是什麼了吧？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"연구선을 되찾아 오시오. 최대한 온전한 상태로 말이야.","JPN":"研究船を取り戻しなさい。できるだけ完全な状態で。","ENG":"Retrieve the research ship. With minimal damage.","TWN":"幫我搶回研究船，並且要盡量維持它的完整！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그러면 당신네 같은 조그만 회사는 상상도 못할 거액을 안겨 주겠소.","JPN":"そうすれば、お前たちのような小さな会社では想像もつかない巨額を支払う。","ENG":"If you do, I'll give you the kind of money that you'd never get in a small company like this.","TWN":"只要幫我把研究船搶回來，我會給你們這種小公司從沒見過的巨款作為酬勞。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"……아, 참고 삼아 말해두지.","JPN":"……ああ、これは参考程度だが。","ENG":"Ah, just so you know...","TWN":"對了……這些話你們聽聽就好。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L10_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"놈들은 관리국 연합 함대가 토벌했던 스캐빈저들의 잔당이오.","JPN":"奴らは管理局連合艦隊が討伐したスカベンジャーの残党だ。","ENG":"They were the remnants of the Scavengers subjugated by the Administration Coalition Fleet.","TWN":"那些傢伙就是管理局聯合艦隊曾經討伐過的清道夫餘黨。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"당신네 용병들은 해적 잡는 해적들이라고 두려워하지만, 그래 봐야 이빨 빠진 호랑이야.","JPN":"傭兵の間では海賊を狩る海賊と恐れられているようだが、しょせん残党は残党。","ENG":"You mercenaries may be afraid of them because they're the pirates that catch pirates. But I'm telling you, they're just toothless tigers.","TWN":"雖然你們這些傭兵其實也跟海盜差不多，但還是比真正的海盜安全一點啦！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그럼 좋은 소식 기다리겠소.","JPN":"では、いい知らせを待っているぞ。","ENG":"Now, I'll wait for the good news.","TWN":"那就等你們的好消息囉！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"단방향 통신으로 인사드리는 건 간만인 것 같네요, 사장님.","JPN":"単方向通信で挨拶するのは久しぶりですね、社長。","ENG":"Boss, it's been a long time since we last talked in simplex mode.","TWN":"老闆好～好像很久沒透過單工通訊跟您問好了。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L15_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"공유해 주신 메시지는 확인했습니다.","JPN":"共有していただいたメッセージは確認しました。","ENG":"I've checked the message you shared.","TWN":"您發來的訊息我收到了。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아시다시피, 현재 펜릴 소대 및 서윤 소대장 모두 다른 임무로 부재 중입니다.","JPN":"ご存知のように、現在フェンリル小隊およびアオイ・シズカ小隊長は別の任務で不在です。","ENG":"As you know, both the Fenrir Squad and Commander Seo Yoon are away on different missions.","TWN":"您也知道，現在芬里爾小隊和徐芸小隊長正外出執行任務中。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그래도 긴급 의뢰라고 하셔서, 일단 대기하고 있던 저희 소대원들을 소집했어요.","JPN":"しかし緊急依頼とおっしゃったので、とりあえず待機していた小隊員を招集しました。","ENG":"As you said this is urgent, I've gathered our available squad members.","TWN":"但又是緊急委託，所以我就招集了待命中的小隊員。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"코핀 함도 작전 중이라 렌탈 업체에서 함선도 한 척 대여해 왔고요.","JPN":"コフィン艦も作戦中なので、レンタル業者から艦船も1隻レンタルしておきました。","ENG":"Because even the Coffin is away on a mission, I've also rented a ship from a rental company.","TWN":"然後科芬艦也在作戰中，所以我就跟出租公司租了一艘艦船。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"다이브도 힘겨워하는 구형 함선이라, 결과는 장담 못 드리겠지만요.","JPN":"ダイブすらギリギリ耐えられる程度の旧型艦船ですから、性能は何とも言えませんが。","ENG":"I'm not sure if this old model can Dive, though.","TWN":"可是是連躍入都有困難的舊型艦船，所以結論就是無法保證打得贏。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그보다…… 의뢰주인 알파트릭스 그룹의 부회장에 대해서입니다만.","JPN":"それより……依頼主のアルファトリックスグループの副会長のことですが。","ENG":"By the way... about our client, the vice chairman of Alphatrix Group.","TWN":"先不管輸贏的事……說到委託人阿爾法崔克斯集團的副會長，"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"이미 저희 외에도 여러 태스크포스에 같은 의뢰를 한 정황이 있습니다.","JPN":"すでに私たち以外にも複数のタスクフォースカンパニーに同じ依頼を出しているとの情報があります。","ENG":"He's hired several other TASKFORCE companies for the same purpose.","TWN":"除了我們之外，他也有委託其他的特遣勢力。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"국제적인 대기업이 연구선 한 척 때문에 이렇게 많은 인력을 동원하다니, 조금 수상하네요.","JPN":"国際的な大手企業が研究船1隻のためにここまで多くの人員を動員するとは、少し怪しいですね。","ENG":"It's a bit suspicious that a big multi-national corporation is outsourcing so much help for the sake of a single research ship.","TWN":"一個規模這麼大的國際企業，竟然為了區區一艘研究船如此大費周章，不覺得有點奇怪嗎？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"한동안 활동이 잠잠하던 스캐빈저 일당들이 다시 나타난 것도 그렇고요.","JPN":"しばらくおとなしくしていたスカベンジャーの一味が再び現れたのもそうです。","ENG":"And that the Scavengers have come out of their hiatus.","TWN":"原本沉寂一陣子的清道夫突然又現身，這點也很奇怪。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"죄송합니다. 쓸데없는 말이 길어졌네요.","JPN":"すみません。雑談が長くなってしまいました。","ENG":"I'm sorry I rambled on.","TWN":"很抱歉，我自顧自地說太多了。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"추가적인 특이사항이 생기면 보고 드리겠습니다. 교신 종료.","JPN":"特異事項が発生したらまた報告します。交信終了。","ENG":"I'll let you know if I find anything else that's suspicious. Over and out.","TWN":"若是有發現到其他的特殊情況，再向老闆報告。結束通訊。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"태스크포스를 연합 단위로 끌어모으다니…….","JPN":"タスクフォースカンパニーを連合単位で集めるとは……","ENG":"Bringing in enough TASKFORCE companies to form its own allied fleet...","TWN":"竟然把特遣勢力都聚集起來……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"과연 대기업이야. 조용히 일을 끝내기는 글렀군.","JPN":"さすが大手企業だ。静かに仕事を終わらせるのは難しそうだな。","ENG":"It's such a big corporation. There's no way this is going to go unnoticed.","TWN":"真不愧是大企業，有錢就是任性。看來事情是無法低調完成了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"아까부터 뭘 하는 거냐, 수집가.","JPN":"さっきから何してるんだ、収集家。","ENG":"What are you doing, Collector?","TWN":"收藏家，我說妳從剛才開始是在忙什麼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"알파트릭스의 통신을 도청 중이야. 연구선을 되찾으려고 용병들을 잔뜩 고용한 모양이군.","JPN":"アルファトリックスの通信を盗聴中だ。研究船を取り戻そうと、大量の傭兵を雇ったようだ。","ENG":"I'm eavesdropping on Alphatrix's communications. It's hired a lot of mercenaries to retrieve that research ship.","TWN":"我在竊聽阿爾法崔克斯的通訊，他們好像僱用了很多傭兵要找回研究船。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"돈에 미친 피라냐들이라면 우리가 오는 족족 박살내면 된다.","JPN":"金に目がないピラニアの群れなら、手当たり次第潰せばいい。","ENG":"Let the money-grubbing piranhas come. We'll destroy them.","TWN":"那些見錢眼開的傢伙，來一個我們就殺一個。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그동안 너는 연구선에서 <color=#ffd34c>머리</color>를 꺼내는 데에나 집중해.","JPN":"その間お前は研究船から<color=#ffd34c>頭部</color>を取り出すことに集中しろ。","ENG":"You just focus on getting the <color=#ffd34c>head</color> out of the ship.","TWN":"這段時間妳只需要專注在，怎麼從研究船上取下<color=#ffd34c>頭</color>就好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"하, 두목한테 말버릇이 건방지네.","JPN":"ああ？　ボスに向かってずいぶんと生意気な口の利き方だな。","ENG":"Hah, that's not how you speak to your boss.","TWN":"哼，你對老大說話這什麼態度！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>강한 자가 지배한다.</color> 그게 너희들 규칙 아니었나?","JPN":"<color=#ffd34c>強い者が支配する。</color> それがお前らのルールだろ？","ENG":"<color=#ffd34c>The strongest rules.</color> Isn't that your rule?","TWN":"<color=#ffd34c>由強者來支配，</color>這不是你們的規則嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"저 연구선은 거대한 폭발물이야. 함부로 건드리면 자료를 파기하기 위해 터져 버릴 걸.","JPN":"あの研究船は巨大な爆弾だ。下手に手を出したら資料を破棄するために爆発してしまう。","ENG":"That research ship is a gigantic bomb. Even the slightest mistake could trigger it to explode and destroy the data it contains.","TWN":"那艘研究船是個巨大的爆炸物，萬一一個不小心，它會為了銷毀資料而自行引爆的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"여기서 보안 시스템을 해제하다 괜히 연구선이 전투에 휘말려서 <color=#ffd34c>머리</color>가 상하기라도 하면 곤란해.","JPN":"ここで下手にセキュリティシステムを解除して、研究船が戦闘に巻き込まれてしまい<color=#ffd34c>頭部</color>に傷でもついたら困る。","ENG":"I don't want to try to disarm its security system from here, either. It could get caught in the crossfire and cause damage to the <color=#ffd34c>head</color>.","TWN":"在這裡解除安全系統後，萬一研究船不小心捲入戰鬥中，傷到<color=#ffd34c>頭</color>的話可就傷腦筋了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그러니 최대한 충돌을 피해 본거지인 서브스톰까지 다이브한다.","JPN":"だからなるべく衝突を避けて、本拠地のサブストームまでダイブする。","ENG":"So, we're going to avoid conflict and Dive back to our base in Substorm first.","TWN":"所以要盡量避開衝突，躍入基地次級風暴。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"내 말 알아들었어, 꼴통?","JPN":"わかったか？","ENG":"Did you hear me, numbskull?","TWN":"聽懂了嗎？飯桶！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"……알겠다. 그렇게 하지.","JPN":"……わかった。そうしよう。","ENG":"... Alright, we'll do that.","TWN":"……知道了，就照妳說的做。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"아. 그리고 한 가지 더.","JPN":"あ、あと一つ。","ENG":"Ah, and one more thing.","TWN":"對了，還有一件事！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"부하들한테 미끼를 뿌리라고 해.","JPN":"部下には餌をばら撒けと伝えろ。","ENG":"Tell your men to set up decoys.","TWN":"叫手下們設下陷阱。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"가짜 구조 신호로 다른 얼치기 해적들을 끌어들이면 용병 놈들도 함부로 못 쫓아올 테니까.","JPN":"偽の救助信号で他の海賊を巻き込めば、傭兵の奴らも混乱するだろう。","ENG":"Use fake rescue signals to attract other half-witted pirates. They'll keep the mercenaries busy for a while.","TWN":"用假的求救訊號把那些笨蛋海盜引過來，這樣那些傭兵應該也不敢貿然追過來吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L3_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"역시 저 여자, 마음에 안 들어.","JPN":"やっぱりあの女、気に食わねえな。","ENG":"I really don't like that woman.","TWN":"我果然不喜歡那女的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L4_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"하는 짓이 꼭 잔머리 굴리는 쥐새끼 같지 않아?","JPN":"やってることがずる賢いを超えて汚ねえっていうか。","ENG":"She's a real weasel, isn't she?","TWN":"做事的手法都跟賊頭賊腦的鼠輩沒兩樣！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어이, 깡통. 아무리 검은 평의회 소속이라고 해도 딱히 우리 편이란 보장은 없잖아.","JPN":"おい、ボロ缶。いくら黒の評議会所属とはいえ、俺らの味方という保障はないだろ。","ENG":"Yo, Tin Can. She may be on the Dark Council, but there's no guarantee she's on our side.","TWN":"喂， 鐵桶！就算她隸屬於暗黑評議會，也不能保證就是我們的人吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"그냥 한눈 팔고 있을 때 뒤에서 찔러 버리자. 어때?","JPN":"やっぱよそ見をしている時に後ろから刺してやろうぜ。","ENG":"Why don't we just stab her in the back while she looks elsewhere? What do you say?","TWN":"乾脆我們趁她分心的時候扯她後腿怎麼樣？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"저 여자가 손가락 하나로 우리 무기들을 전부 가지고 놀던 걸 벌써 잊었나?","JPN":"あの女が指一本で俺たちの武器をオモチャにしたのを忘れたのか？","ENG":"Did you forget how she can control all our weapons with a wave of her finger?","TWN":"你忘記那個女人是怎麼用一根手指頭，就把我們的武器都拿去把玩的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"까불지 말고 규칙에 따라라.","JPN":"余計なことを言うのはそれぐらいにして、ルールに従え。","ENG":"Don't get any ideas. Just follow the rule.","TWN":"不要想那些有的沒有，規則既然訂了就要遵守！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"스캐빈저에선 제일 센 놈이 대장이다.","JPN":"スカベンジャーでは一番強い奴が頭だ。","ENG":"Among us Scavengers, the strongest rules.","TWN":"在清道夫裡，最強的人就是隊長！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"난 그 규칙 정말 마음에 안 들어.","JPN":"俺はよ、そのルールが気に食わねえんだよ！","ENG":"I really don't like that rule.","TWN":"老實說那個規則我也覺得莫名其妙。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"애초에 두목이 알파트릭스한테 머리만 안 뺏겼어도 이럴 일 없잖아.","JPN":"そもそもボスがアルファトリックスに頭部さえ取られなければこんなことする必要なかっただろ。","ENG":"This wouldn't have happened if the Boss didn't lose her head to Alphatrix.","TWN":"如果一開始老大的頭沒有被阿爾法崔克斯搶走，根本也不會有這些事！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"저 여자의 능력은 두목의 머릴 되찾는 데 유용하다.","JPN":"あの女の能力はボスの頭部を取り戻すために使える。","ENG":"That woman can help us get her head back.","TWN":"那女人的能力可以幫助我們找回老大的頭。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그러니 일단은 시키는 대로 해.","JPN":"だから今は言われたとおりにしろ。","ENG":"So, do as she says for now.","TWN":"我們就先暫且聽命於她吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"말했다시피, 스캐빈저는 제일 센 놈이 대장이니까.","JPN":"さっきも言ったとおり、スカベンジャーでは一番強い奴が頭だ。","ENG":"Don't forget: the strongest rules among us Scavengers.","TWN":"而且就如同我剛才所說的，在清道夫裡，最強的人就是隊長！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"아아…… 그래! 두목만 돌아오면 저 비실비실한 여자는 한 주먹거리도 아니지!","JPN":"ああ……そうだな！　ボスさえ戻って来れば、あのガリガリ女は足元にも及ばないぜ！","ENG":"Ah... Yes! Once the Boss is back, that frail brat won't be a problem anymore.","TWN":"吼……好啦！等老大回來，肯定會給那個女人好看！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"히히, 자기가 두목을 다른 기계처럼 마음대로 조종할 수 있을 거라고 믿는 모양이던데.","JPN":"ヒヒヒ、自分がボスを他の機械みたいに簡単に操れると勘違いしてるようだが。","ENG":"Heh heh. She thinks she can control the Boss like other machines.","TWN":"嘿嘿～她好像以為老大像其他機械一樣，可以任由她控制。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어디 두고 보자고.","JPN":"どうなるか楽しみだな。","ENG":"We'll see if that's true.","TWN":"走著瞧吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};